function solve(nums: number[], queries: number[][]): number[] {
    // Helper function to count set bits
    function countSetBits(x: number): number {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    // Helper function to compute depth
    function getDepth(x: number): number {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = countSetBits(current);
            depth++;
        }
        return depth;
    }

    // Fenwick Tree class
    class FenwickTree {
        private tree: number[];
        private size: number;
        constructor(size: number) {
            this.size = size;
            this.tree = new Array(size + 1).fill(0);
        }
        update(index: number, delta: number): void {
            index += 1; // convert to 1-based
            while (index <= this.size) {
                this.tree[index] += delta;
                index += index & -index;
            }
        }
        query(index: number): number {
            index += 1; // convert to 1-based
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }
        rangeQuery(l: number, r: number): number {
            return this.query(r) - this.query(l - 1);
        }
    }

    const n = nums.length;
    const depthArray = nums.map(num => getDepth(num));
    const fenwickTrees: FenwickTree[] = [];
    for (let k = 0; k <= 5; k++) {
        fenwickTrees.push(new FenwickTree(n));
    }

    // Initialize the Fenwick Trees
    for (let i = 0; i < n; i++) {
        const d = depthArray[i];
        if (d >= 0 && d <= 5) {
            fenwickTrees[d].update(i, 1);
        }
    }

    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const l = query[1];
            const r = query[2];
            const k = query[3];
            if (k < 0 || k > 5) {
                answer.push(0);
                continue;
            }
            const ft = fenwickTrees[k];
            const count = ft.rangeQuery(l, r);
            answer.push(count);
        } else {
            const idx = query[1];
            const val = query[2];
            const oldVal = nums[idx];
            const oldDepth = depthArray[idx];
            const newDepth = getDepth(val);
            // Update the Fenwick Trees for oldDepth and newDepth
            if (oldDepth >= 0 && oldDepth <= 5) {
                fenwickTrees[oldDepth].update(idx, -1);
            }
            // Update the nums array
            nums[idx] = val;
            // Update the depthArray
            depthArray[idx] = newDepth;
            if (newDepth >= 0 && newDepth <= 5) {
                fenwickTrees[newDepth].update(idx, 1);
            }
        }
    }
    return answer;
}

