public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int maxDepth = 5;
        FenwickTree[] fenwickTrees = new FenwickTree[maxDepth + 1];
        for (int k = 0; k <= maxDepth; k++) {
            fenwickTrees[k] = new FenwickTree(n);
        }

        int[] depthArray = new int[n];
        for (int i = 0; i < n; i++) {
            depthArray[i] = getDepth(nums[i]);
        }

        for (int i = 0; i < n; i++) {
            int d = depthArray[i];
            if (d >= 0 && d <= maxDepth) {
                fenwickTrees[d].update(i, 1);
            }
        }

        long[] answer = new long[queries.length];
