        for (int k = 0; k <= maxDepth; k++) {
            fenwickTrees[k] = new FenwickTree(n);
        }

        long[] depthArray = new long[n];
        for (int i = 0; i < n; i++) {
            depthArray[i] = getDepth(nums[i]);
        }

        for (int i = 0; i < n; i++) {
            int d = (int) depthArray[i];
            if (d >= 0 && d <= maxDepth) {
                fenwickTrees[d].update(i, 1);
            }
        }

        long[] answer = new long[queries.length];
        int idx = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                if (k < 0 || k > maxDepth) {
                    answer[idx++] = 0;
                    continue;
                }
                FenwickTree ft = fenwickTrees[k];
                long count = ft.rangeQuery(l, r);
                answer[idx++] = count;
            } else {
                int idxVal = (int) query[1];
                long val = query[2];
                long oldValue = nums[idxVal];
