                depthArray[idxVal] = newDepth;

                if (newDepth >= 0 && newDepth <= maxDepth) {
                    fenwickTrees[newDepth].update(idxVal, 1);
                }
            }
        }

        return answer;
    }

    static class FenwickTree {
        private long[] tree;
        private int size;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new long[size + 1]; // 1-based indexing
        }

        public void update(int index, long delta) {
            index += 1; // convert to 1-based
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public long query(int index) {
            index += 1; // convert to 1-based
            long res = 0;
            while (index > 0) {
                res += tree[index];
                index -= index & -index;
            }
            return res;
        }

        public long rangeQuery(int l, int r) {
            return query(r) - query(l - 1);
        }
    }

    static long countSetBits(long x) {
        long count = 0;
        while (x != 0) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    static int getDepth(long x) {
        int depth = 0;
        while (x != 1) {
            x = countSetBits(x);
            depth++;
        }
