                this.tree[index] += delta;
                index += index & -index;
            }
        }
        query(index: number): number {
            index += 1; // convert to 1-based
            let res = 0;
            while (index > 0) {
                res += this.tree[index];
                index -= index & -index;
            }
            return res;
        }
        rangeQuery(l: number, r: number): number {
            return this.query(r) - this.query(l - 1);
        }
    }

    const n = nums.length;
    const depthArray = nums.map(num => getDepth(num));
    const fenwickTrees: FenwickTree[] = [];
    for (let k = 0; k <= 5; k++) {
        fenwickTrees.push(new FenwickTree(n));
    }

    // Initialize the Fenwick Trees
    for (let i = 0; i < n; i++) {
        const d = depthArray[i];
        if (d >= 0 && d <= 5) {
            fenwickTrees[d].update(i, 1);
        }
    }

    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const l = query[1];
            const r = query[2];
            const k = query[3];
            if (k < 0 || k > 5) {
                answer.push(0);
                continue;
            }
            const ft = fenwickTrees[k];
            const count = ft.rangeQuery(l, r);
            answer.push(count);
        } else {
            const idx = query[1];
            const val = query[2];
            const oldVal = nums[idx];
            const oldDepth = depthArray[idx];
            const newDepth = getDepth(val);
            // Update the Fenwick Trees for oldDepth and newDepth
            if (oldDepth >= 0 && oldDepth <= 5) {
                fenwickTrees[oldDepth].update(idx, -1);
            }
            // Update the nums array
            nums[idx] = val;
            // Update the depthArray
            depthArray[idx] = newDepth;
            if (newDepth >= 0 && newDepth <= 5) {
                fenwickTrees[newDepth].update(idx, 1);
            }
        }
    }
    return answer;
}
